import cv2
import numpy as np
from flask import Flask, request, jsonify
from sklearn import preprocessing

app = Flask(__name__)

# Load LBPH (Local Binary Patterns Histograms) Face Recognizer
recognizer = cv2.face.LBPHFaceRecognizer_create()

# Load training data
recognizer.read('employee_faces.xml')  # Assuming the model is trained and saved as 'employee_faces.xml'

@app.route('/api/facial_recognition', methods=['POST'])
def facial_recognition():
    file = request.files['image']
    file_path = f"temp/{file.filename}"
    file.save(file_path)

    # Load the image file
    image = cv2.imread(file_path, cv2.IMREAD_GRAYSCALE)

    # Perform face recognition
    label, confidence = recognizer.predict(image)

    return jsonify({'label': label, 'confidence': confidence})

if __name__ == '__main__':
    app.run(debug=True)